/**
 * raw_decoder.js — thin JS wrapper around the LibRaw WebAssembly module.
 *
 * Provides:
 *   decodeRAW(arrayBuffer) → Promise<{width, height, data: Uint16Array}>
 *
 * `data` is linear-light RGB uint16 (0=black, 65535=sensor clip).
 * Apply ACES tone mapping before displaying.
 *
 * The WASM module (libraw.js + libraw.wasm) must be served from the same
 * directory as this file.  They are auto-generated by wasm/build.sh.
 */
'use strict';

let _mod = null;           // cached Emscripten module instance
let _loadPromise = null;   // in-flight load promise

async function _loadLibRaw() {
    if (_mod) return _mod;
    if (_loadPromise) return _loadPromise;

    _loadPromise = new Promise((resolve, reject) => {
        const script = document.createElement('script');
        // Resolve relative to this file's URL so it works from any origin path.
        const base = document.currentScript?.src
            ? new URL('.', document.currentScript.src).href
            : location.href;
        script.src = new URL('libraw.js', base).href;
        script.onload = () => {
            // LibRawModule is the Emscripten-generated factory function.
            LibRawModule({
                locateFile: name => new URL(name, base).href,
            }).then(m => { _mod = m; resolve(m); }).catch(reject);
        };
        script.onerror = () => reject(new Error('Failed to load libraw.js'));
        document.head.appendChild(script);
    });
    return _loadPromise;
}

/**
 * Decode any RAW camera file (DNG, CR2, CR3, NEF, ARW, …) from an ArrayBuffer.
 * Returns linear-light uint16 RGB suitable for ACES tone mapping.
 */
async function decodeRAW(arrayBuffer) {
    const m = await _loadLibRaw();

    const bytes = new Uint8Array(arrayBuffer);

    // Copy file bytes into WASM heap.
    const filePtr = m._malloc(bytes.byteLength);
    if (!filePtr) throw new Error('LibRaw: out of WASM memory');
    m.HEAPU8.set(bytes, filePtr);

    // Allocate output-dimension slots (4 bytes each = int32).
    const wPtr = m._malloc(4);
    const hPtr = m._malloc(4);

    const dataPtr = m._libraw_decode(filePtr, bytes.byteLength, wPtr, hPtr);
    m._free(filePtr);

    if (!dataPtr) {
        m._free(wPtr); m._free(hPtr);
        throw new Error('LibRaw: decode failed — unsupported or corrupted file');
    }

    const w = m.getValue(wPtr, 'i32');
    const h = m.getValue(hPtr, 'i32');
    m._free(wPtr);
    m._free(hPtr);

    // Copy uint16 RGB out of WASM heap before freeing.
    const n = w * h * 3;                      // total uint16 values
    const data = new Uint16Array(n);
    const halfPtr = dataPtr >>> 1;             // byte → uint16 index
    data.set(m.HEAPU16.subarray(halfPtr, halfPtr + n));

    m._libraw_free(dataPtr);

    return { width: w, height: h, data };     // data: linear uint16 RGB
}
